import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getCarbonCreditData(walletAddress) {
  const balances = await client.BalanceService.getTokenBalancesForWalletAddress(
    "matic-mainnet", walletAddress
  );
  const carbonTokens = (balances.data?.items ?? []).filter(
    item => item.contract_ticker_symbol?.startsWith("TCO2") ||
            item.contract_name?.toLowerCase().includes("carbon")
  );
  return carbonTokens;
}
